node --loader ./scripts/ts-extension-loader.mjs --input-type=module -e '
import { mkdtempSync, rmSync, writeFileSync, mkdirSync } from "fs";
import { tmpdir } from "os";
import path from "path";
import {
  createYpiStudioTask,
  bindYpiStudioTaskToContext,
  transitionYpiStudioTask,
  recordYpiStudioUserApproval,
  getYpiStudioTaskDetail,
} from "./lib/ypi-studio-tasks.ts";

const root = mkdtempSync(path.join(tmpdir(), "ypi-own2b-"));
try {
  const s1 = "pi_s1";
  const s2 = "pi_s2";
  const created = createYpiStudioTask({ cwd: root, title: "approval transfer", contextId: s1 });
  // force awaiting_approval + grant as s1 without full plan-review gates by writing task.json directly is hard.
  // Instead: set meta after create by binding path.
  // Use transition with override to awaiting_approval may need plan-review. Skip full transition.
  // Direct bind transfer with synthetic grant via second create path:
  const taskPath = path.join(root, ".ypi", "tasks", created.id, "task.json");
  const { readFileSync } = await import("fs");
  const raw = JSON.parse(readFileSync(taskPath, "utf8"));
  raw.status = "awaiting_approval";
  raw.meta = {
    approvalGate: { enteredAt: "2026-01-01T00:00:00.000Z", from: "planning", to: "awaiting_approval", contextId: s1 },
    approvalGrant: { approvedAt: "2026-01-01T00:00:01.000Z", contextId: s1, inputHash: "abc", source: "user-input" },
  };
  writeFileSync(taskPath, JSON.stringify(raw, null, 2));
  const after = bindYpiStudioTaskToContext(root, created.id, s2);
  console.log("after transfer contexts", after.contextIds);
  console.log("grant cleared", !after.meta?.approvalGrant, after.meta?.approvalGrant);
  try {
    transitionYpiStudioTask(created.id, { cwd: root, to: "implementing", contextId: s2, override: true });
    console.log("FAIL: implement without new grant");
  } catch (e) {
    console.log("implement blocked:", e.message.slice(0, 100));
  }
  // archived bind
  raw.status = "archived";
  // reload after bind
  const raw2 = JSON.parse(readFileSync(taskPath, "utf8"));
  // archive is special path; just mark archived via loadTaskRecord uses folder. Skip.
  console.log("done");
} finally {
  rmSync(root, { recursive: true, force: true });
}
' 2>&1 | tail -20",
  "timeout": 60
}

